function VideoBackdrop({ src, className = '', overlayClassName = '' }: { src: string; className?: string; overlayClassName?: string }) {
  return (
    <div className={`absolute inset-0 overflow-hidden ${className}`}>
      <video className="h-full w-full object-cover" autoPlay loop muted playsInline preload="auto" src={src} />
      <div className={`absolute inset-0 bg-gradient-to-b from-black/10 via-black/40 to-black ${overlayClassName}`} />
    </div>
  );
}

function HlsBackdropVideo() {
  const videoRef = useRef<HTMLVideoElement | null>(null);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) {
      return;
    }

    if (video.canPlayType('application/vnd.apple.mpegurl')) {
      video.src = streamingSource;
      return;
    }

    if (Hls.isSupported()) {
      const hls = new Hls({
        enableWorker: true
      });

      hls.loadSource(streamingSource);
      hls.attachMedia(video);

      return () => {
        hls.destroy();
      };
    }

    video.src = streamingSource;
  }, []);

  return <video ref={videoRef} className="h-full w-full object-cover opacity-70" autoPlay loop muted playsInline preload="auto" />;
}

function RevealWord({ word, scrollYProgress, start, end }: { word: string; scrollYProgress: MotionValue<number>; start: number; end: number }) {
  const opacity = useTransform(scrollYProgress, [start, end], [0.15, 1]);

  return (
    <motion.span style={{ opacity }} className="inline-block">
      {word}
    </motion.span>
  );
}

function MissionWords({ text, scrollYProgress }: { text: string; scrollYProgress: MotionValue<number> }) {
  const words = text.split(' ');

  return (
    <span className="inline-flex flex-wrap gap-x-2 gap-y-1">
      {words.map((word, index) => (
        <RevealWord key={`${word}-${index}`} word={word} scrollYProgress={scrollYProgress} start={index / Math.max(words.length, 1)} end={(index + 1) / Math.max(words.length, 1)} />
      ))}
    </span>
  );
}

