'use client';

import { useEffect, useRef, useState, type FormEvent } from 'react';
import { Bot, LoaderCircle, Send, X } from 'lucide-react';

type ChatRole = 'system' | 'user' | 'assistant';

type Message = {
  id: string;
  role: ChatRole;
  content: string;
};

type AiChatModalProps = {
  open: boolean;
  onClose: () => void;
};

const initialMessages: Message[] = [
  {
    id: 'assistant-1',
    role: 'assistant',
    content: 'Welcome to सन्देश. Ask for an outline, a rewrite, or a concise strategic answer.'
  }
];

function toRequestMessages(messages: Message[]) {
  return messages.map(({ role, content }) => ({ role, content }));
}

export default function AiChatModal({ open, onClose }: AiChatModalProps) {
  const [chatHistory, setChatHistory] = useState<Message[]>(initialMessages);
  const [input, setInput] = useState('');
  const [isSending, setIsSending] = useState(false);
  const viewportRef = useRef<HTMLDivElement | null>(null);
  const inputRef = useRef<HTMLInputElement | null>(null);

  useEffect(() => {
    if (open) {
      window.setTimeout(() => inputRef.current?.focus(), 20);
    }
  }, [open]);

  useEffect(() => {
    viewportRef.current?.scrollTo({ top: viewportRef.current.scrollHeight, behavior: 'smooth' });
  }, [chatHistory, open]);

  useEffect(() => {
    if (!open) {
      setInput('');
      setIsSending(false);
      setChatHistory(initialMessages);
    }
  }, [open]);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();

    const content = input.trim();
    if (!content || isSending) {
      return;
    }

    const userMessage: Message = {
      id: crypto.randomUUID(),
      role: 'user',
      content
    };

    const nextMessages = [...chatHistory, userMessage];
    setChatHistory(nextMessages);
    setInput('');
    setIsSending(true);

    try {
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ messages: toRequestMessages(nextMessages) })
      });

      const data = (await response.json()) as { message?: string; error?: string; detail?: string };

      if (!response.ok) {
        throw new Error(data.error ?? data.detail ?? 'The chat service returned an error.');
      }

      setChatHistory((current) => [
        ...current,
        {
          id: crypto.randomUUID(),
          role: 'assistant',
          content: data.message?.trim() || 'No response was returned by the model.'
        }
      ]);
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Something went wrong.';

      setChatHistory((current) => [
        ...current,
        {
          id: crypto.randomUUID(),
          role: 'assistant',
          content: message
        }
      ]);
    } finally {
      setIsSending(false);
    }
  }

  if (!open) {
    return null;
  }

  return (
    <div className="fixed inset-0 z-[90] flex items-center justify-center px-4 py-6">
      <button
        type="button"
        aria-label="Close chat"
        className="absolute inset-0 bg-black/80 backdrop-blur-xl"
        onClick={onClose}
      />

      <div className="liquid-glass relative z-10 flex max-h-[min(86vh,820px)] w-full max-w-4xl flex-col rounded-[2rem] border border-white/10 bg-card/80 text-white shadow-2xl shadow-black/70">
        <header className="flex items-center justify-between border-b border-white/10 px-5 py-4 sm:px-7">
          <div className="flex items-center gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-full border border-white/15 bg-white/5">
              <Bot className="h-5 w-5 text-white" />
            </div>
            <div>
              <p className="text-sm font-semibold tracking-[0.3em] text-white/65">सन्देश AI</p>
              <p className="text-sm text-white/45">Secure Nvidia Nemotron chat route</p>
            </div>
          </div>

          <button
            type="button"
            aria-label="Close modal"
            onClick={onClose}
            className="liquid-glass relative flex h-10 w-10 items-center justify-center rounded-full border border-white/10 text-white/80 transition hover:bg-white/5"
          >
            <X className="h-4 w-4" />
          </button>
        </header>

        {/* Flexible Scroll Container */}
        <div
          ref={viewportRef}
          className="flex-1 space-y-4 overflow-y-auto px-5 py-5 sm:px-7 max-h-[450px]"
        >
          {chatHistory.map((message) => (
            <div key={message.id} className={message.role === 'user' ? 'flex justify-end' : 'flex justify-start'}>
              <div
                className={[
                  'max-w-[85%] rounded-[1.5rem] px-5 py-3 text-sm leading-6 break-words whitespace-pre-wrap',
                  message.role === 'user'
                    ? 'liquid-glass border border-white/10 bg-white/10 text-white'
                    : 'border border-white/10 bg-white/5 text-white/90'
                ].join(' ')}
              >
                {message.content}
              </div>
            </div>
          ))}

          {isSending ? (
            <div className="flex justify-start">
              <div className="flex items-center gap-3 text-sm text-white/55 bg-white/5 px-4 py-2 rounded-full border border-white/5">
                <LoaderCircle className="h-4 w-4 animate-spin text-white/70" />
                Nemotron is composing a response...
              </div>
            </div>
          ) : null}
        </div>

        <form onSubmit={handleSubmit} className="border-t border-white/10 p-4 sm:p-5">
          <div className="liquid-glass flex items-center gap-3 rounded-full border border-white/10 bg-black/40 px-4 py-2.5">
            <input
              ref={inputRef}
              value={input}
              onChange={(event) => setInput(event.target.value)}
              placeholder="Message the portal..."
              className="min-w-0 flex-1 bg-transparent text-sm text-white outline-none placeholder:text-white/35"
            />
            <button
              type="submit"
              disabled={isSending}
              className="liquid-glass inline-flex h-10 w-10 items-center justify-center rounded-full border border-white/10 text-white transition hover:bg-white/10 disabled:cursor-not-allowed disabled:opacity-50"
            >
              <Send className="h-4 w-4" />
            </button>
          </div>
          <p className="mt-3 text-xs text-white/35">History is forwarded to the server route and never sent directly to NVIDIA from the client.</p>
        </form>
      </div>
    </div>
  );
}